import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Switch, Redirect } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Zoom from './components/Zoom';
import MicrosoftTeams from './components/MicrosoftTeams';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/chrome';
import FileExplorer from './components/FileExplorer';
import './App.css';

const App = () => {
  const [activeComponent, setActiveComponent] = useState(null);

  return (
    <Router>
      <div className="App">
        {/* Sidebar va rămâne neschimbat */}
        <Sidebar activeComponent={activeComponent} setActiveComponent={setActiveComponent} />

        {/* Gestionăm rutele pentru componente */}
        <Switch>
          <Route exact path="/">
            {/* Componenta implicită (de exemplu, FileExplorer) */}
            <FileExplorer />
          </Route>
          <Route path="/zoom">
            <Zoom />
          </Route>
          <Route path="/teams">
            <MicrosoftTeams />
          </Route>
          <Route path="/word">
            <MicrosoftWord />
          </Route>
          <Route path="/excel">
            <MicrosoftExcel />
          </Route>
          <Route path="/powerpoint">
            <PowerPoint />
          </Route>
          <Route path="/pdf">
            <PDFReader />
          </Route>
          <Route path="/chrome">
            <Chrome />
          </Route>
          {/* Dacă nimic nu se potrivește, redirecționează la FileExplorer */}
          <Redirect to="/" />
        </Switch>
      </div>
    </Router>
  );
};

export default App;
